assert len(V) == len(recs), f"V has {len(V)} but {len(recs)} records"
with open(os.path.join(OUT, "verdicts.jsonl"), "w") as f:
    for i, r in enumerate(recs):
        verdict, causa, just = V[i]
        f.write(json.dumps({
            "id": r["id"],
            "idx": i,
            "cve": r["cve_norm"],
            "scanner": r["scanner"],
            "reported_by": r["reported_by"],
            "distro": r["distro"],
            "stratum": r["stratum"],
            "verdict": verdict,
            "causa": causa,
            "justificativa": just,
        }, ensure_ascii=False) + "\n")
print("wrote", len(recs), "verdicts")
